const body = $json.body.data.body || '';
const from = $json.body.data.from || '';
const sessionId = $json.body.sessionId || '';

// Extract just the phone number (remove @c.us)
const phoneNumber = from.replace('@c.us', '');

// Simple keyword detection
const lowerBody = body.toLowerCase();
let replyText = '';

if (lowerBody.includes('hi') || lowerBody.includes('hello') || lowerBody.includes('مرحبا') || lowerBody.includes('هلا')) {
  replyText = `Hello! 👋 How can I help you today?\nمرحباً! 👋 كيف يمكنني مساعدتك اليوم؟`;
} else if (lowerBody.includes('price') || lowerBody.includes('سعر') || lowerBody.includes('كم')) {
  replyText = `Please contact our sales team for pricing.\nيرجى التواصل مع فريق المبيعات للاستفسار عن الأسعار.`;
} else {
  replyText = `Thank you for your message! We'll get back to you soon.\nشكراً لتواصلك! سنرد عليك قريباً.`;
}

return { phoneNumber, sessionId, replyText };

const data = $json.body.data || {};
const sessionId = $json.body.sessionId || '';
console.log('Non-text message received:', data.type, 'from session:', sessionId);
return { handled: false, type: data.type, sessionId };
